  dateFrom: string;
  isBold?: boolean;
  colorMode?: CashflowTablePeriodCellColorMode;
  onClick?: () => void;
};

type CashflowTablePeriodNumberCellProps = CashflowTablePeriodCellBaseProps & {
  kind: "number";
  value: number;
  progressPercentage?: number;
  currency?: never;
  balanceQuality?: never;
  children?: never;
};

type CashflowTablePeriodSummaryCellProps = CashflowTablePeriodCellBaseProps & {
  kind: "summary";
  value: number | null;
  currency: string;
  balanceQuality?: BalanceQuality | null;
  progressPercentage?: never;
  children?: never;
};

type CashflowTablePeriodCustomCellProps = CashflowTablePeriodCellBaseProps & {
  kind: "custom";
  value?: number | null; // optional semantic value for shared colorMode logic
  children: ReactNode;
  progressPercentage?: never;
  currency?: never;
  balanceQuality?: never;
};

export type CashflowTablePeriodCellProps =
  | CashflowTablePeriodNumberCellProps
  | CashflowTablePeriodSummaryCellProps
  | CashflowTablePeriodCustomCellProps;
```

Flat props are intentional here: they keep `React.memo` shallow-comparison-friendly and avoid passing around nested config objects.

## 2. Usage example

