  kind="summary"
  value={period.income} // or period.costs
  currency={currency}
  columnIndex={index}
  dateFrom={period.dateFrom}
  isBold
  colorMode="none"
/>

// Future bespoke content
<CashflowTablePeriodCell
  kind="custom"
  value={period.netBalance}
  columnIndex={index}
  dateFrom={period.dateFrom}
  colorMode="balance"
>
  <MyFuturePeriodContent period={period} />
